import { useState } from 'react';
import { Outlet, useNavigate, useLocation } from 'react-router-dom';
import { Layout, Menu, theme } from 'antd';
import type { MenuProps } from 'antd';

const { Header, Content, Footer } = Layout;

interface MenuItem {
  key: string;
  label: string;
  path: string;
}

// 菜单配置 - 添加新页面时在这里追加
const menuItems: MenuItem[] = [
  // 示例：{ key: 'users', label: '用户管理', path: '/users' }
];

const BasicLayout: React.FC = () => {
  const [collapsed, setCollapsed] = useState(false);
  const navigate = useNavigate();
  const location = useLocation();

  const {
    token: { colorBgContainer, borderRadiusLG },
  } = theme.useToken();

  const items: MenuProps['items'] = menuItems.map((item) => ({
    key: item.key,
    label: item.label,
    onClick: () => navigate(item.path),
  }));

  const currentKey = menuItems.find((item) => location.pathname === item.path)?.key || '';

  return (
    <Layout style={{ minHeight: '100vh' }}>
      <Header
        style={{
          display: 'flex',
          alignItems: 'center',
          background: colorBgContainer,
          padding: '0 24px',
        }}
      >
        <div style={{ fontSize: '20px', fontWeight: 'bold', marginRight: '24px' }}>
          系统名称
        </div>
        <Menu
          theme="light"
          mode="horizontal"
          selectedKeys={[currentKey]}
          items={items}
          style={{ flex: 1, minWidth: 0 }}
        />
      </Header>
      <Content style={{ padding: '24px 48px' }}>
        <div
          style={{
            background: colorBgContainer,
            borderRadius: borderRadiusLG,
            minHeight: 'calc(100vh - 112px)',
            padding: 24,
          }}
        >
          <Outlet />
        </div>
      </Content>
      <Footer style={{ textAlign: 'center' }}>
        系统名称 ©{new Date().getFullYear()} Created with Ant Design
      </Footer>
    </Layout>
  );
};

export default BasicLayout;

